  /// Result from a MAVLink command (MAV_CMD)
  ///
  /// MAV_RESULT
  enum MAV_RESULT : uint8_t {
    /// Command is valid (is supported and has valid parameters), and was
    /// executed.
    ///
    /// MAV_RESULT_ACCEPTED
    MAV_RESULT_ACCEPTED = 0,
    /// Command is valid, but cannot be executed at this time. This is used to
    /// indicate a problem that should be fixed just by waiting (e.g. a state
    /// machine is busy, can't arm because have not got GPS lock, etc.).
    /// Retrying later should work.
    ///
    /// MAV_RESULT_TEMPORARILY_REJECTED
    MAV_RESULT_TEMPORARILY_REJECTED = 1,
    /// Command is invalid (is supported but has invalid parameters). Retrying
    /// same command and parameters will not work.
    ///
    /// MAV_RESULT_DENIED
    MAV_RESULT_DENIED = 2,
    /// Command is not supported (unknown).
    ///
    /// MAV_RESULT_UNSUPPORTED
    MAV_RESULT_UNSUPPORTED = 3,
    /// Command is valid, but execution has failed. This is used to indicate any
    /// non-temporary or unexpected problem, i.e. any problem that must be fixed
    /// before the command can succeed/be retried. For example, attempting to
    /// write a file when out of memory, attempting to arm when sensors are not
    /// calibrated, etc.
    ///
    /// MAV_RESULT_FAILED
    MAV_RESULT_FAILED = 4,
    /// Command is valid and is being executed. This will be followed by further
    /// progress updates, i.e. the component may send further COMMAND_ACK
    /// messages with result MAV_RESULT_IN_PROGRESS (at a rate decided by the
    /// implementation), and must terminate by sending a COMMAND_ACK message
    /// with final result of the operation. The COMMAND_ACK.progress field can
    /// be used to indicate the progress of the operation. There is no need for
    /// the sender to retry the command, but if done during execution, the
    /// component will return MAV_RESULT_IN_PROGRESS with an updated progress.
    ///
    /// MAV_RESULT_IN_PROGRESS
    MAV_RESULT_IN_PROGRESS = 5,
    /// Command is only accepted when sent as a COMMAND_LONG.
    ///
    /// MAV_RESULT_COMMAND_LONG_ONLY
    MAV_RESULT_COMMAND_LONG_ONLY = 7,
    /// Command is only accepted when sent as a COMMAND_INT.
    ///
    /// MAV_RESULT_COMMAND_INT_ONLY
    MAV_RESULT_COMMAND_INT_ONLY = 8
  };

  /// Result of mission operation (in a MISSION_ACK message).
