    /// MAVLink type: uint16_t
    ///
    /// errors_count1
    uint16_t errors_count1;
    /// Autopilot-specific errors
    ///
    /// MAVLink type: uint16_t
    ///
    /// errors_count2
    uint16_t errors_count2;
    /// Autopilot-specific errors
    ///
    /// MAVLink type: uint16_t
    ///
    /// errors_count3
    uint16_t errors_count3;
    /// Autopilot-specific errors
    ///
    /// MAVLink type: uint16_t
    ///
    /// errors_count4
