    /// x
    int32_t x;
    /// PARAM6 / y position: local: x position in meters * 1e4, global:
    /// longitude in degrees *10^7
    ///
    /// MAVLink type: int32_t
    ///
    /// y
    int32_t y;
    /// PARAM7 / z position: global: altitude in meters (relative or absolute,
