    /// induces a positive flow. Sensor linear motion along the positive Y axis
    /// induces a negative flow.)
    ///
    /// MAVLink type: float
    ///
    /// units: rad
    ///
    /// integrated_x
    float integrated_x;
    /// Flow in radians around Y axis (Sensor RH rotation about the Y axis
    /// induces a positive flow. Sensor linear motion along the positive X axis
    /// induces a positive flow.)
    ///
    /// MAVLink type: float
    ///
    /// units: rad
    ///
    /// integrated_y
    float integrated_y;
    /// RH rotation around X axis
    ///
    /// MAVLink type: float
    ///
    /// units: rad
    ///
    /// integrated_xgyro
    float integrated_xgyro;
    /// RH rotation around Y axis
    ///
    /// MAVLink type: float
    ///
    /// units: rad
    ///
    /// integrated_ygyro
    float integrated_ygyro;
    /// RH rotation around Z axis
    ///
    /// MAVLink type: float
    ///
    /// units: rad
    ///
    /// integrated_zgyro
    float integrated_zgyro;
    /// Time since the distance was sampled.
    ///
    /// MAVLink type: uint32_t
    ///
    /// units: us
    ///
    /// time_delta_distance_us
    uint32_t time_delta_distance_us;
    /// Distance to the center of the flow field. Positive value (including
    /// zero): distance known. Negative value: Unknown distance.
    ///
    /// MAVLink type: float
    ///
    /// units: m
    ///
    /// distance
    float distance;
    /// Temperature
    ///
    /// MAVLink type: int16_t
    ///
    /// units: cdegC
    ///
    /// temperature
    int16_t temperature;
    /// Sensor ID
    ///
    /// MAVLink type: uint8_t
    ///
    /// sensor_id
    uint8_t sensor_id;
    /// Optical flow quality / confidence. 0: no valid flow, 255: maximum
    /// quality
    ///
    /// MAVLink type: uint8_t
    ///
    /// quality
    uint8_t quality;
