  ///
  /// LOG_DATA
  inline constexpr uint32_t log_data_MSG_ID = 120;
  inline constexpr uint8_t log_data_CRC_EXTRA = 134;
  inline constexpr size_t log_data_ENCODED_LENGTH = 97;
  struct log_data {
    /// Offset into the log
    ///
    /// MAVLink type: uint32_t
    ///
    /// ofs
    uint32_t ofs;
    /// Log id (from LOG_ENTRY reply)
    ///
    /// MAVLink type: uint16_t
    ///
    /// id
    uint16_t id;
    /// Number of bytes (zero for end of log)
    ///
    /// MAVLink type: uint8_t
    ///
    /// units: bytes
    ///
    /// count
    uint8_t count;
    /// log data
    ///
    /// MAVLink type: uint8_t[90]
    ///
    /// data
    uint8_t data[90];
  };
  using log_data_t = log_data;

  inline void log_data_serialize(const log_data& msg, uint8_t* data) {
    mavlink_memset_s(data, log_data_ENCODED_LENGTH, 0, log_data_ENCODED_LENGTH);
    mavlink_put_uint32(data, log_data_ENCODED_LENGTH, 0, msg.ofs);
    mavlink_put_uint16(data, log_data_ENCODED_LENGTH, 4, msg.id);
    mavlink_put_uint8(data, log_data_ENCODED_LENGTH, 6, msg.count);
    for (size_t i = 0; i < 90; i++) {
      mavlink_put_uint8(data, log_data_ENCODED_LENGTH, 7 + i * 1, msg.data[i]);
    }
  }

  inline void log_data_parse(const uint8_t* data, log_data& msg) {
    msg.ofs = mavlink_get_uint32(data, 0);
    msg.id = mavlink_get_uint16(data, 4);
    msg.count = mavlink_get_uint8(data, 6);
    for (size_t i = 0; i < 90; i++) {
      msg.data[i] = mavlink_get_uint8(data, 7 + i * 1);
    }
  }

