  /// Control a serial port. This can be used for raw access to an onboard
  /// serial peripheral such as a GPS or telemetry radio. It is designed to make
  /// it possible to update the devices firmware via MAVLink messages or change
  /// the devices settings. A message with zero bytes can be used to change just
  /// the baudrate.
  ///
  /// SERIAL_CONTROL
  inline constexpr uint32_t serial_control_MSG_ID = 126;
  inline constexpr uint8_t serial_control_CRC_EXTRA = 220;
  inline constexpr size_t serial_control_ENCODED_LENGTH = 79;
  struct serial_control {
    /// Baudrate of transfer. Zero means no change.
    ///
    /// MAVLink type: uint32_t
    ///
    /// units: bits/s
    ///
    /// baudrate
    uint32_t baudrate;
    /// Timeout for reply data
    ///
    /// MAVLink type: uint16_t
    ///
    /// units: ms
    ///
    /// timeout
    uint16_t timeout;
    /// Serial control device type.
    ///
    /// MAVLink type: uint8_t
    ///
    /// enum: [SERIAL_CONTROL_DEV]
    ///
    /// device
    SERIAL_CONTROL_DEV device;
    /// Bitmap of serial control flags.
    ///
    /// MAVLink type: uint8_t
    ///
    /// enum: [SERIAL_CONTROL_FLAG]
    ///
    /// flags
    uint8_t flags;
    /// how many bytes in this transfer
    ///
    /// MAVLink type: uint8_t
    ///
    /// units: bytes
    ///
    /// count
    uint8_t count;
    /// serial data
    ///
    /// MAVLink type: uint8_t[70]
    ///
    /// data
    uint8_t data[70];
  };
