  inline void serial_control_serialize(const serial_control& msg, uint8_t* data) {
    mavlink_memset_s(data, serial_control_ENCODED_LENGTH, 0, serial_control_ENCODED_LENGTH);
    mavlink_put_uint32(data, serial_control_ENCODED_LENGTH, 0, msg.baudrate);
    mavlink_put_uint16(data, serial_control_ENCODED_LENGTH, 4, msg.timeout);
    mavlink_put_uint8(data, serial_control_ENCODED_LENGTH, 6, static_cast<uint8_t>(msg.device));
    mavlink_put_uint8(data, serial_control_ENCODED_LENGTH, 7, msg.flags);
    mavlink_put_uint8(data, serial_control_ENCODED_LENGTH, 8, msg.count);
    for (size_t i = 0; i < 70; i++) {
      mavlink_put_uint8(data, serial_control_ENCODED_LENGTH, 9 + i * 1, msg.data[i]);
    }
  }

  inline void serial_control_parse(const uint8_t* data, serial_control& msg) {
    msg.baudrate = mavlink_get_uint32(data, 0);
    msg.timeout = mavlink_get_uint16(data, 4);
    msg.device = static_cast<SERIAL_CONTROL_DEV>(mavlink_get_uint8(data, 6));
    msg.flags = mavlink_get_uint8(data, 7);
    msg.count = mavlink_get_uint8(data, 8);
    for (size_t i = 0; i < 70; i++) {
      msg.data[i] = mavlink_get_uint8(data, 9 + i * 1);
    }
  }

