  inline void distance_sensor_serialize(const distance_sensor& msg, uint8_t* data) {
    mavlink_memset_s(data, distance_sensor_ENCODED_LENGTH, 0, distance_sensor_ENCODED_LENGTH);
    mavlink_put_uint32(data, distance_sensor_ENCODED_LENGTH, 0, msg.time_boot_ms);
    mavlink_put_uint16(data, distance_sensor_ENCODED_LENGTH, 4, msg.min_distance);
    mavlink_put_uint16(data, distance_sensor_ENCODED_LENGTH, 6, msg.max_distance);
    mavlink_put_uint16(data, distance_sensor_ENCODED_LENGTH, 8, msg.current_distance);
    mavlink_put_uint8(data, distance_sensor_ENCODED_LENGTH, 10, static_cast<uint8_t>(msg.type));
    mavlink_put_uint8(data, distance_sensor_ENCODED_LENGTH, 11, msg.id);
    mavlink_put_uint8(data, distance_sensor_ENCODED_LENGTH, 12, static_cast<uint8_t>(msg.orientation));
    mavlink_put_uint8(data, distance_sensor_ENCODED_LENGTH, 13, msg.covariance);
    mavlink_put_float(data, distance_sensor_ENCODED_LENGTH, 14, msg.horizontal_fov);
    mavlink_put_float(data, distance_sensor_ENCODED_LENGTH, 18, msg.vertical_fov);
    for (size_t i = 0; i < 4; i++) {
      mavlink_put_float(data, distance_sensor_ENCODED_LENGTH, 22 + i * 4, msg.quaternion[i]);
    }
    mavlink_put_uint8(data, distance_sensor_ENCODED_LENGTH, 38, msg.signal_quality);
  }

  inline void distance_sensor_parse(const uint8_t* data, distance_sensor& msg) {
    msg.time_boot_ms = mavlink_get_uint32(data, 0);
    msg.min_distance = mavlink_get_uint16(data, 4);
    msg.max_distance = mavlink_get_uint16(data, 6);
    msg.current_distance = mavlink_get_uint16(data, 8);
    msg.type = static_cast<MAV_DISTANCE_SENSOR>(mavlink_get_uint8(data, 10));
    msg.id = mavlink_get_uint8(data, 11);
    msg.orientation = static_cast<MAV_SENSOR_ORIENTATION>(mavlink_get_uint8(data, 12));
    msg.covariance = mavlink_get_uint8(data, 13);
    msg.horizontal_fov = mavlink_get_float(data, 14);
    msg.vertical_fov = mavlink_get_float(data, 18);
    for (size_t i = 0; i < 4; i++) {
      msg.quaternion[i] = mavlink_get_float(data, 22 + i * 4);
    }
    msg.signal_quality = mavlink_get_uint8(data, 38);
  }

