    ///
    /// units: degE7
    ///
    /// lat
    int32_t lat;
    /// Longitude of SW corner of first grid
    ///
    /// MAVLink type: int32_t
    ///
    /// units: degE7
    ///
    /// lon
    int32_t lon;
    /// Grid spacing
    ///
    /// MAVLink type: uint16_t
    ///
    /// units: m
    ///
    /// grid_spacing
    uint16_t grid_spacing;
    /// Terrain data MSL
    ///
    /// MAVLink type: int16_t[16]
    ///
    /// units: m
    ///
    /// data
    int16_t data[16];
