    /// non-monotonic (it might reset on events like GPS lock or when a new QNH
    /// value is set). It should be the altitude to which global altitude
    /// waypoints are compared to. Note that it is *not* the GPS altitude,
    /// however, most GPS modules already output MSL by default and not the
    /// WGS84 altitude.
    ///
    /// MAVLink type: float
    ///
    /// units: m
    ///
    /// altitude_amsl
    float altitude_amsl;
    /// This is the local altitude in the local coordinate frame. It is not the
    /// altitude above home, but in reference to the coordinate origin (0, 0,
    /// 0). It is up-positive.
    ///
    /// MAVLink type: float
    ///
    /// units: m
    ///
    /// altitude_local
    float altitude_local;
    /// This is the altitude above the home position. It resets on each change
    /// of the current home position.
    ///
    /// MAVLink type: float
    ///
    /// units: m
    ///
    /// altitude_relative
    float altitude_relative;
    /// This is the altitude above terrain. It might be fed by a terrain
    /// database or an altimeter. Values smaller than -1000 should be
    /// interpreted as unknown.
    ///
    /// MAVLink type: float
    ///
    /// units: m
    ///
    /// altitude_terrain
    float altitude_terrain;
