    /// external reactions
    ///
    /// MAVLink type: uint8_t
    ///
    /// enum: [MAV_BATTERY_CHARGE_STATE]
    ///
    /// Extensions field for MAVLink 2.
    ///
    /// charge_state
    MAV_BATTERY_CHARGE_STATE charge_state;
