    /// for this battery should have a value of 0, where zero indicates not
    /// supported (note, this is different than for the voltages field and
    /// allows empty byte truncation). If the measured value is 0 then 1 should
    /// be sent instead.
    ///
    /// MAVLink type: uint16_t[4]
    ///
    /// units: mV
    ///
    /// Extensions field for MAVLink 2.
    ///
    /// voltages_ext
    uint16_t voltages_ext[4];
