  using battery_status_t = battery_status;

  inline void battery_status_serialize(const battery_status& msg, uint8_t* data) {
    mavlink_memset_s(data, battery_status_ENCODED_LENGTH, 0, battery_status_ENCODED_LENGTH);
    mavlink_put_int32(data, battery_status_ENCODED_LENGTH, 0, msg.current_consumed);
    mavlink_put_int32(data, battery_status_ENCODED_LENGTH, 4, msg.energy_consumed);
    mavlink_put_int16(data, battery_status_ENCODED_LENGTH, 8, msg.temperature);
    for (size_t i = 0; i < 10; i++) {
      mavlink_put_uint16(data, battery_status_ENCODED_LENGTH, 10 + i * 2, msg.voltages[i]);
    }
    mavlink_put_int16(data, battery_status_ENCODED_LENGTH, 30, msg.current_battery);
    mavlink_put_uint8(data, battery_status_ENCODED_LENGTH, 32, msg.id);
    mavlink_put_uint8(data, battery_status_ENCODED_LENGTH, 33, static_cast<uint8_t>(msg.battery_function));
    mavlink_put_uint8(data, battery_status_ENCODED_LENGTH, 34, static_cast<uint8_t>(msg.type));
    mavlink_put_int8(data, battery_status_ENCODED_LENGTH, 35, msg.battery_remaining);
    mavlink_put_int32(data, battery_status_ENCODED_LENGTH, 36, msg.time_remaining);
    mavlink_put_uint8(data, battery_status_ENCODED_LENGTH, 40, static_cast<uint8_t>(msg.charge_state));
    for (size_t i = 0; i < 4; i++) {
      mavlink_put_uint16(data, battery_status_ENCODED_LENGTH, 41 + i * 2, msg.voltages_ext[i]);
    }
    mavlink_put_uint8(data, battery_status_ENCODED_LENGTH, 49, static_cast<uint8_t>(msg.mode));
    mavlink_put_uint32(data, battery_status_ENCODED_LENGTH, 50, msg.fault_bitmask);
  }

  inline void battery_status_parse(const uint8_t* data, battery_status& msg) {
    msg.current_consumed = mavlink_get_int32(data, 0);
    msg.energy_consumed = mavlink_get_int32(data, 4);
    msg.temperature = mavlink_get_int16(data, 8);
    for (size_t i = 0; i < 10; i++) {
      msg.voltages[i] = mavlink_get_uint16(data, 10 + i * 2);
    }
    msg.current_battery = mavlink_get_int16(data, 30);
    msg.id = mavlink_get_uint8(data, 32);
    msg.battery_function = static_cast<MAV_BATTERY_FUNCTION>(mavlink_get_uint8(data, 33));
    msg.type = static_cast<MAV_BATTERY_TYPE>(mavlink_get_uint8(data, 34));
    msg.battery_remaining = mavlink_get_int8(data, 35);
    msg.time_remaining = mavlink_get_int32(data, 36);
    msg.charge_state = static_cast<MAV_BATTERY_CHARGE_STATE>(mavlink_get_uint8(data, 40));
    for (size_t i = 0; i < 4; i++) {
      msg.voltages_ext[i] = mavlink_get_uint16(data, 41 + i * 2);
    }
    msg.mode = static_cast<MAV_BATTERY_MODE>(mavlink_get_uint8(data, 49));
    msg.fault_bitmask = mavlink_get_uint32(data, 50);
  }

  /// Version and capability of autopilot software. This should be emitted in
  /// response to a request with MAV_CMD_REQUEST_MESSAGE.
  ///
  /// AUTOPILOT_VERSION
  inline constexpr uint32_t autopilot_version_MSG_ID = 148;
  inline constexpr uint8_t autopilot_version_CRC_EXTRA = 178;
  inline constexpr size_t autopilot_version_ENCODED_LENGTH = 78;
  struct autopilot_version {
    /// Bitmap of capabilities
    ///
    /// MAVLink type: uint64_t
    ///
    /// enum: [MAV_PROTOCOL_CAPABILITY]
    ///
    /// capabilities
    uint64_t capabilities;
    /// UID if provided by hardware (see uid2)
    ///
    /// MAVLink type: uint64_t
    ///
    /// uid
    uint64_t uid;
    /// Firmware version number
    ///
    /// MAVLink type: uint32_t
    ///
    /// flight_sw_version
    uint32_t flight_sw_version;
    /// Middleware version number
    ///
    /// MAVLink type: uint32_t
    ///
    /// middleware_sw_version
    uint32_t middleware_sw_version;
    /// Operating system version number
    ///
    /// MAVLink type: uint32_t
    ///
    /// os_sw_version
    uint32_t os_sw_version;
    /// HW / board version (last 8 bits should be silicon ID, if any). The first
    /// 16 bits of this field specify
    /// https://github.com/ardupilot/ardupilot/blob/master/Tools/AP_Bootloader/board_types.txt
    ///
    /// MAVLink type: uint32_t
    ///
    /// board_version
    uint32_t board_version;
    /// ID of the board vendor
    ///
    /// MAVLink type: uint16_t
    ///
    /// vendor_id
    uint16_t vendor_id;
    /// ID of the product
    ///
    /// MAVLink type: uint16_t
    ///
    /// product_id
    uint16_t product_id;
    /// Custom version field, commonly the first 8 bytes of the git hash. This
    /// is not an unique identifier, but should allow to identify the commit
    /// using the main version number even for very large code bases.
    ///
    /// MAVLink type: uint8_t[8]
    ///
    /// flight_custom_version
    uint8_t flight_custom_version[8];
    /// Custom version field, commonly the first 8 bytes of the git hash. This
    /// is not an unique identifier, but should allow to identify the commit
    /// using the main version number even for very large code bases.
    ///
    /// MAVLink type: uint8_t[8]
    ///
    /// middleware_custom_version
    uint8_t middleware_custom_version[8];
    /// Custom version field, commonly the first 8 bytes of the git hash. This
    /// is not an unique identifier, but should allow to identify the commit
    /// using the main version number even for very large code bases.
    ///
    /// MAVLink type: uint8_t[8]
    ///
    /// os_custom_version
    uint8_t os_custom_version[8];
    /// UID if provided by hardware (supersedes the uid field. If this is
    /// non-zero, use this field, otherwise use uid)
    ///
    /// MAVLink type: uint8_t[18]
    ///
    /// Extensions field for MAVLink 2.
    ///
    /// uid2
    uint8_t uid2[18];
  };
  using autopilot_version_t = autopilot_version;

  inline void autopilot_version_serialize(const autopilot_version& msg, uint8_t* data) {
    mavlink_memset_s(data, autopilot_version_ENCODED_LENGTH, 0, autopilot_version_ENCODED_LENGTH);
    mavlink_put_uint64(data, autopilot_version_ENCODED_LENGTH, 0, msg.capabilities);
    mavlink_put_uint64(data, autopilot_version_ENCODED_LENGTH, 8, msg.uid);
    mavlink_put_uint32(data, autopilot_version_ENCODED_LENGTH, 16, msg.flight_sw_version);
    mavlink_put_uint32(data, autopilot_version_ENCODED_LENGTH, 20, msg.middleware_sw_version);
    mavlink_put_uint32(data, autopilot_version_ENCODED_LENGTH, 24, msg.os_sw_version);
    mavlink_put_uint32(data, autopilot_version_ENCODED_LENGTH, 28, msg.board_version);
    mavlink_put_uint16(data, autopilot_version_ENCODED_LENGTH, 32, msg.vendor_id);
    mavlink_put_uint16(data, autopilot_version_ENCODED_LENGTH, 34, msg.product_id);
    for (size_t i = 0; i < 8; i++) {
      mavlink_put_uint8(data, autopilot_version_ENCODED_LENGTH, 36 + i * 1, msg.flight_custom_version[i]);
    }
    for (size_t i = 0; i < 8; i++) {
      mavlink_put_uint8(data, autopilot_version_ENCODED_LENGTH, 44 + i * 1, msg.middleware_custom_version[i]);
    }
    for (size_t i = 0; i < 8; i++) {
      mavlink_put_uint8(data, autopilot_version_ENCODED_LENGTH, 52 + i * 1, msg.os_custom_version[i]);
    }
    for (size_t i = 0; i < 18; i++) {
      mavlink_put_uint8(data, autopilot_version_ENCODED_LENGTH, 60 + i * 1, msg.uid2[i]);
    }
  }

  inline void autopilot_version_parse(const uint8_t* data, autopilot_version& msg) {
    msg.capabilities = mavlink_get_uint64(data, 0);
    msg.uid = mavlink_get_uint64(data, 8);
    msg.flight_sw_version = mavlink_get_uint32(data, 16);
    msg.middleware_sw_version = mavlink_get_uint32(data, 20);
    msg.os_sw_version = mavlink_get_uint32(data, 24);
    msg.board_version = mavlink_get_uint32(data, 28);
    msg.vendor_id = mavlink_get_uint16(data, 32);
    msg.product_id = mavlink_get_uint16(data, 34);
    for (size_t i = 0; i < 8; i++) {
      msg.flight_custom_version[i] = mavlink_get_uint8(data, 36 + i * 1);
    }
    for (size_t i = 0; i < 8; i++) {
      msg.middleware_custom_version[i] = mavlink_get_uint8(data, 44 + i * 1);
    }
    for (size_t i = 0; i < 8; i++) {
      msg.os_custom_version[i] = mavlink_get_uint8(data, 52 + i * 1);
    }
    for (size_t i = 0; i < 18; i++) {
      msg.uid2[i] = mavlink_get_uint8(data, 60 + i * 1);
    }
  }

