    ///
    /// units: us
    ///
    /// time_usec
    uint64_t time_usec;
    /// Velocity innovation test ratio
    ///
    /// MAVLink type: float
    ///
    /// vel_ratio
    float vel_ratio;
    /// Horizontal position innovation test ratio
    ///
    /// MAVLink type: float
    ///
