    ///
    /// pos_vert_ratio
    float pos_vert_ratio;
    /// Magnetometer innovation test ratio
    ///
    /// MAVLink type: float
    ///
    /// mag_ratio
    float mag_ratio;
    /// Height above terrain innovation test ratio
    ///
    /// MAVLink type: float
    ///
    /// hagl_ratio
    float hagl_ratio;
    /// True airspeed innovation test ratio
    ///
    /// MAVLink type: float
    ///
    /// tas_ratio
    float tas_ratio;
    /// Horizontal position 1-STD accuracy relative to the EKF local origin
    ///
    /// MAVLink type: float
    ///
    /// units: m
