  /// RTCM message for injecting into the onboard GPS (used for DGPS)
  ///
  /// GPS_RTCM_DATA
  inline constexpr uint32_t gps_rtcm_data_MSG_ID = 233;
  inline constexpr uint8_t gps_rtcm_data_CRC_EXTRA = 35;
  inline constexpr size_t gps_rtcm_data_ENCODED_LENGTH = 182;
  struct gps_rtcm_data {
    /// LSB: 1 means message is fragmented, next 2 bits are the fragment ID, the
    /// remaining 5 bits are used for the sequence ID. Messages are only to be
    /// flushed to the GPS when the entire message has been reconstructed on the
    /// autopilot. The fragment ID specifies which order the fragments should be
    /// assembled into a buffer, while the sequence ID is used to detect a
    /// mismatch between different buffers. The buffer is considered fully
    /// reconstructed when either all 4 fragments are present, or all the
    /// fragments before the first fragment with a non full payload is received.
    /// This management is used to ensure that normal GPS operation doesn't
    /// corrupt RTCM data, and to recover from a unreliable transport delivery
    /// order.
    ///
    /// MAVLink type: uint8_t
    ///
    /// flags
    uint8_t flags;
    /// data length
    ///
    /// MAVLink type: uint8_t
    ///
    /// units: bytes
    ///
    /// len
    uint8_t len;
    /// RTCM message (may be fragmented)
    ///
    /// MAVLink type: uint8_t[180]
    ///
    /// data
    uint8_t data[180];
  };
  using gps_rtcm_data_t = gps_rtcm_data;

  inline void gps_rtcm_data_serialize(const gps_rtcm_data& msg, uint8_t* data) {
    mavlink_memset_s(data, gps_rtcm_data_ENCODED_LENGTH, 0, gps_rtcm_data_ENCODED_LENGTH);
    mavlink_put_uint8(data, gps_rtcm_data_ENCODED_LENGTH, 0, msg.flags);
    mavlink_put_uint8(data, gps_rtcm_data_ENCODED_LENGTH, 1, msg.len);
    for (size_t i = 0; i < 180; i++) {
      mavlink_put_uint8(data, gps_rtcm_data_ENCODED_LENGTH, 2 + i * 1, msg.data[i]);
    }
  }

  inline void gps_rtcm_data_parse(const uint8_t* data, gps_rtcm_data& msg) {
    msg.flags = mavlink_get_uint8(data, 0);
    msg.len = mavlink_get_uint8(data, 1);
    for (size_t i = 0; i < 180; i++) {
      msg.data[i] = mavlink_get_uint8(data, 2 + i * 1);
    }
  }

