  /// Status text message. These messages are printed in yellow in the COMM
  /// console of QGroundControl. WARNING: They consume quite some bandwidth, so
  /// use only for important status and error messages. If implemented wisely,
  /// these messages are buffered on the MCU and sent only at a limited rate
  /// (e.g. 10 Hz).
  ///
  /// STATUSTEXT
  inline constexpr uint32_t statustext_MSG_ID = 253;
  inline constexpr uint8_t statustext_CRC_EXTRA = 83;
  inline constexpr size_t statustext_ENCODED_LENGTH = 54;
  struct statustext {
    /// Severity of status. Relies on the definitions within RFC-5424.
    ///
    /// MAVLink type: uint8_t
    ///
    /// enum: [MAV_SEVERITY]
    ///
    /// severity
    MAV_SEVERITY severity;
    /// Status text message, without null termination character
    ///
    /// MAVLink type: char[50]
    ///
    /// text
    char text[50];
    /// Unique (opaque) identifier for this statustext message. May be used to
    /// reassemble a logical long-statustext message from a sequence of chunks.
    /// A value of zero indicates this is the only chunk in the sequence and the
    /// message can be emitted immediately.
    ///
    /// MAVLink type: uint16_t
    ///
    /// Extensions field for MAVLink 2.
    ///
    /// id
    uint16_t id;
    /// This chunk's sequence number; indexing is from zero. Any null character
    /// in the text field is taken to mean this was the last chunk.
    ///
    /// MAVLink type: uint8_t
    ///
    /// Extensions field for MAVLink 2.
    ///
    /// chunk_seq
    uint8_t chunk_seq;
  };
  using statustext_t = statustext;

  inline void statustext_serialize(const statustext& msg, uint8_t* data) {
    mavlink_memset_s(data, statustext_ENCODED_LENGTH, 0, statustext_ENCODED_LENGTH);
    mavlink_put_uint8(data, statustext_ENCODED_LENGTH, 0, static_cast<uint8_t>(msg.severity));
    mavlink_put_bytes(data, statustext_ENCODED_LENGTH, 1, reinterpret_cast<const uint8_t*>(msg.text), 50);
    mavlink_put_uint16(data, statustext_ENCODED_LENGTH, 51, msg.id);
    mavlink_put_uint8(data, statustext_ENCODED_LENGTH, 53, msg.chunk_seq);
  }

  inline void statustext_parse(const uint8_t* data, statustext& msg) {
    msg.severity = static_cast<MAV_SEVERITY>(mavlink_get_uint8(data, 0));
    mavlink_get_bytes(data, 1, reinterpret_cast<uint8_t*>(msg.text), 50, 50);
    msg.id = mavlink_get_uint16(data, 51);
    msg.chunk_seq = mavlink_get_uint8(data, 53);
  }

