    uint8_t target_system;
    /// Component ID.
    ///
    /// MAVLink type: uint8_t
    ///
    /// target_component
    uint8_t target_component;
    /// bus number
    ///
    /// MAVLink type: uint8_t
    ///
    /// bus
    uint8_t bus;
    /// what operation to perform on the filter list. See CAN_FILTER_OP enum.
    ///
    /// MAVLink type: uint8_t
