    mavlink_memset_s(data, can_filter_modify_ENCODED_LENGTH, 0, can_filter_modify_ENCODED_LENGTH);
    for (size_t i = 0; i < 16; i++) {
      mavlink_put_uint16(data, can_filter_modify_ENCODED_LENGTH, 0 + i * 2, msg.ids[i]);
    }
    mavlink_put_uint8(data, can_filter_modify_ENCODED_LENGTH, 32, msg.target_system);
    mavlink_put_uint8(data, can_filter_modify_ENCODED_LENGTH, 33, msg.target_component);
